import{_ as t,c as s,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"Tools: Core Modes | opencode-supermemory","description":"Master supermemory's 5 core tools: add, search, profile, list, forget. Control Agent memory via natural language commands.","frontmatter":{"title":"Tools: Core Modes | opencode-supermemory","sidebarTitle":"Core Tools","subtitle":"Tools Explained: Teaching Agents to Remember","description":"Master supermemory's 5 core tools: add, search, profile, list, forget. Control Agent memory via natural language commands.","tags":["Tool Usage","Memory Management","Core Features"],"prerequisite":["start-getting-started"],"order":999},"headers":[],"relativePath":"supermemoryai/opencode-supermemory/core/tools/index.md","filePath":"supermemoryai/opencode-supermemory/core/tools/index.md"}`),i={name:"supermemoryai/opencode-supermemory/core/tools/index.md"};function n(r,e,l,d,p,c){return o(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="tools-explained-teaching-agents-to-remember" tabindex="-1">Tools Explained: Teaching Agents to Remember <a class="header-anchor" href="#tools-explained-teaching-agents-to-remember" aria-label="Permalink to &quot;Tools Explained: Teaching Agents to Remember&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>In this lesson, you will master the core interaction methods of the <code>supermemory</code> plugin. Although Agents usually manage memory automatically, as a developer, you often need to intervene manually.</p><p>By the end of this lesson, you will be able to:</p><ol><li>Use <code>add</code> mode to manually save key technical decisions.</li><li>Use <code>search</code> mode to verify if the Agent remembers your preferences.</li><li>Use <code>profile</code> to view the &quot;you&quot; from the Agent&#39;s perspective.</li><li>Use <code>list</code> and <code>forget</code> to clean up outdated or incorrect memories.</li></ol><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>opencode-supermemory is not a black box; it interacts with the Agent via the standard OpenCode Tool protocol. This means you can call it like a function or direct the Agent to use it with natural language.</p><p>The plugin registers a tool named <code>supermemory</code> to the Agent, which acts like a Swiss Army knife with 6 modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Function</th><th>Typical Scenario</th></tr></thead><tbody><tr><td><strong>add</strong></td><td>Add memory</td><td>&quot;Remember, this project must run with Bun&quot;</td></tr><tr><td><strong>search</strong></td><td>Search memory</td><td>&quot;Did I say how to handle authentication before?&quot;</td></tr><tr><td><strong>profile</strong></td><td>User profile</td><td>View the coding habits summarized by the Agent</td></tr><tr><td><strong>list</strong></td><td>List memories</td><td>Audit the last 10 saved memories</td></tr><tr><td><strong>forget</strong></td><td>Delete memory</td><td>Delete an incorrect configuration record</td></tr><tr><td><strong>help</strong></td><td>Guide</td><td>View tool help documentation</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Automatic Trigger Mechanism</p><p>In addition to manual calls, the plugin also listens to your chat content. When you say &quot;Remember this&quot; or &quot;Save this&quot; in natural language, the plugin automatically detects keywords and forces the Agent to call the <code>add</code> tool.</p></div><h2 id="follow-me-managing-memory-manually" tabindex="-1">Follow Me: Managing Memory Manually <a class="header-anchor" href="#follow-me-managing-memory-manually" aria-label="Permalink to &quot;Follow Me: Managing Memory Manually&quot;">​</a></h2><p>Although we usually let the Agent operate automatically, manual tool invocation is very useful during debugging or establishing initial memories. You can ask the Agent to perform these operations directly via natural language in the OpenCode dialog box.</p><h3 id="_1-add-memory-add" tabindex="-1">1. Add Memory (Add) <a class="header-anchor" href="#_1-add-memory-add" aria-label="Permalink to &quot;1. Add Memory (Add)&quot;">​</a></h3><p>This is the most common feature. You can specify the content, type, and scope of the memory.</p><p><strong>Action</strong>: Tell the Agent to save a memory about the project architecture.</p><p><strong>Input Command</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use the supermemory tool to save a memory:</span></span>
<span class="line"><span>Content: &quot;All service layer code in this project must be placed in the src/services directory&quot;</span></span>
<span class="line"><span>Type: architecture</span></span>
<span class="line"><span>Scope: project</span></span></code></pre></div><p><strong>Agent&#39;s Internal Behavior</strong> (Source Logic):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;add&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;All service layer code in this project must be placed in the src/services directory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;architecture&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>You Should See</strong>: The Agent returns a confirmation message similar to this:</p><blockquote><p>✅ Memory added to project scope (ID: mem_12345...)</p></blockquote><div class="tip custom-block"><p class="custom-block-title">Choosing Memory Type</p><p>To make retrieval more precise, it is recommended to use accurate types:</p><ul><li><code>project-config</code>: Tech stack, toolchain configuration</li><li><code>architecture</code>: Architecture patterns, directory structure</li><li><code>preference</code>: Your personal coding preferences (e.g., &quot;prefer arrow functions&quot;)</li><li><code>error-solution</code>: Specific solutions to certain errors</li><li><code>learned-pattern</code>: Code patterns observed by the Agent</li></ul></div><h3 id="_2-search-memory-search" tabindex="-1">2. Search Memory (Search) <a class="header-anchor" href="#_2-search-memory-search" aria-label="Permalink to &quot;2. Search Memory (Search)&quot;">​</a></h3><p>When you want to confirm if the Agent &quot;knows&quot; something, you can use the search function.</p><p><strong>Action</strong>: Search for memories about &quot;service layer&quot;.</p><p><strong>Input Command</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Query supermemory, keyword is &quot;services&quot;, scope is project</span></span></code></pre></div><p><strong>Agent&#39;s Internal Behavior</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;search&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;services&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>You Should See</strong>: The Agent lists relevant memory fragments and their similarity scores.</p><h3 id="_3-view-user-profile-profile" tabindex="-1">3. View User Profile (Profile) <a class="header-anchor" href="#_3-view-user-profile-profile" aria-label="Permalink to &quot;3. View User Profile (Profile)&quot;">​</a></h3><p>Supermemory automatically maintains a &quot;user profile&quot; containing your long-term preferences.</p><p><strong>Action</strong>: View your profile.</p><p><strong>Input Command</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Call the profile mode of the supermemory tool to see what you know about me</span></span></code></pre></div><p><strong>You Should See</strong>: Two types of information returned:</p><ul><li><strong>Static</strong>: Static facts (e.g., &quot;User is a full-stack engineer&quot;)</li><li><strong>Dynamic</strong>: Dynamic preferences (e.g., &quot;User has been focusing on Rust recently&quot;)</li></ul><h3 id="_4-audit-and-forget-list-forget" tabindex="-1">4. Audit and Forget (List &amp; Forget) <a class="header-anchor" href="#_4-audit-and-forget-list-forget" aria-label="Permalink to &quot;4. Audit and Forget (List &amp; Forget)&quot;">​</a></h3><p>If the Agent remembers incorrect information (such as a deprecated API Key), you need to delete it.</p><p><strong>Step 1: List recent memories</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>List the last 5 project memories</span></span></code></pre></div><p><em>(Agent calls <code>mode: &quot;list&quot;, limit: 5</code>)</em></p><p><strong>Step 2: Get ID and delete</strong> Suppose you see an incorrect memory with ID <code>mem_abc123</code>.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Delete the record with memory ID mem_abc123</span></span></code></pre></div><p><em>(Agent calls <code>mode: &quot;forget&quot;, memoryId: &quot;mem_abc123&quot;</code>)</em></p><p><strong>You Should See</strong>:</p><blockquote><p>✅ Memory mem_abc123 removed from project scope</p></blockquote><h2 id="advanced-natural-language-triggers" tabindex="-1">Advanced: Natural Language Triggers <a class="header-anchor" href="#advanced-natural-language-triggers" aria-label="Permalink to &quot;Advanced: Natural Language Triggers&quot;">​</a></h2><p>You don&#39;t need to describe tool parameters in detail every time. The plugin has built-in keyword detection mechanisms.</p><p><strong>Try It</strong>: Say directly in the conversation:</p><blockquote><p><strong>Remember this</strong>: All date handling must use the date-fns library, moment.js is prohibited.</p></blockquote><p><strong>What Happened?</strong></p><ol><li>The plugin&#39;s <code>chat.message</code> hook detected the keyword &quot;Remember this&quot;.</li><li>The plugin injected a system prompt into the Agent: <code>[MEMORY TRIGGER DETECTED]</code>.</li><li>The Agent received the instruction: &quot;You MUST use the supermemory tool with mode: &#39;add&#39;...&quot;.</li><li>The Agent automatically extracted the content and called the tool.</li></ol><p>This is a very natural interaction method, allowing you to &quot;solidify&quot; knowledge at any time during the coding process.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Q: What is the default <code>scope</code>?</strong> A: The default is <code>project</code>. If you want to save preferences common across projects (e.g., &quot;I always use TypeScript&quot;), please explicitly specify <code>scope: &quot;user&quot;</code>.</p><p><strong>Q: Why didn&#39;t the memory I added take effect immediately?</strong> A: The <code>add</code> operation is asynchronous. Usually, the Agent &quot;knows&quot; the new memory immediately after the tool call succeeds, but under extreme network latency, it may take a few seconds.</p><p><strong>Q: Is sensitive information uploaded?</strong> A: The plugin automatically masks content within <code>&lt;private&gt;</code> tags. However, for security, it is recommended not to put passwords or API Keys into memory.</p><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code location</strong></summary><blockquote><p>Last Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Tool Definition</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr><tr><td>Keyword Detection</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Trigger Prompts</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L20-L28" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>20-28</td></tr><tr><td>Client Implementation</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/client.ts" target="_blank" rel="noreferrer"><code>src/services/client.ts</code></a></td><td>Full File</td></tr></tbody></table><p><strong>Key Type Definitions</strong>:</p><ul><li><code>MemoryType</code>: Defined in <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li><li><code>MemoryScope</code>: Defined in <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li></ul></details><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><blockquote><p>Next lesson we will learn <strong><a href="./../memory-management/">Memory Scopes &amp; Lifecycle</a></strong>.</p><p>You will learn:</p><ul><li>Underlying isolation mechanisms of User Scope and Project Scope</li><li>How to design efficient memory partitioning strategies</li><li>Memory lifecycle management</li></ul></blockquote>`,63)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
